const vector = res.data[0].embedding  // float[1536]

// Cosine similarity
const similarity = (a, b) =>
  a.reduce((sum, v, i) => sum + v * b[i], 0) /
  (Math.sqrt(a.reduce((s, v) => s + v*v, 0)) * Math.sqrt(b.reduce((s, v) => s + v*v, 0)))
